fusion_FUSION.signalValueToName = function(value){
    for (var property in fusion_FUSION.signals) {
        if (fusion_FUSION.signals.hasOwnProperty(property)) {
            if(fusion_FUSION.signals[property]==value)
                return property;
        }
    }
    return undefined;
}

fusion_FUSION.signalNameToValue = function(name){
    return fusion_FUSION.signals[name];
}



fusion_FUSION.createDoubleCheckMatrix = function(){
    var matrix = new fusion_FUSION.Matrix();
    for (var r in matrix) {
        if (matrix.hasOwnProperty(r)) {
            var row = matrix[r];
            for (var c in row) {
                if (row.hasOwnProperty(c)) {
                    if(r !== c )
                        matrix[r][c] = "Do nothing";
                }
            }
        }
    }
    return matrix;
}

fusion_FUSION.createSelectiveSignalsMatrix = function (){
    var matrix = new fusion_FUSION.Matrix();
    for (var r in matrix) {
        if (matrix.hasOwnProperty(r)) {
            var row = matrix[r];
            for (var c in row) {
                if (row.hasOwnProperty(c)) {
                    if(r == "Do nothing")
                        matrix[r][c] = "Do nothing";
                    if(c == "Do nothing")
                        matrix[r][c] = "Do nothing";
                }
            }
        }
    }
    return matrix;
}

fusion_FUSION.uniqueId		=	function () {
    function s4() {
        return Math.floor((1 + Math.random()) * 0x10000)
            .toString(16)
            .substring(1);
    }
    return new Date().getTime() + '@' + s4() + s4() + '-' + s4() + '-' + s4() + '-' +
        s4() + '-' + s4() + s4() + s4();
};

fusion_FUSION.getAvailableScript = function(key) {
    if (typeof SERVICES === 'undefined') return fusion_FUSION.scripts[key];
    else if (!fusion_FUSION.scripts[key].subscriptionPack) return fusion_FUSION.scripts[key];
    else if (SERVICES.payments.isSubscriptionPackEnabled(fusion_FUSION.scripts[key].subscriptionPack)) return fusion_FUSION.scripts[key];
    else return null;
};

fusion_FUSION.getScript = function(key) {
    return fusion_FUSION.scripts[key];
};

fusion_FUSION.getAvailableScripts = function() {
    if (fusion_FUSION.availableScripts) return fusion_FUSION.availableScripts;
    fusion_FUSION.availableScripts = JSON.parse(JSON.stringify(fusion_FUSION.scripts));

    const keys = Object.keys(fusion_FUSION.availableScripts);

    for (let key of keys) {
        const script = fusion_FUSION.availableScripts[key];

        if (typeof SERVICES === 'undefined' || (script.subscriptionPack && !SERVICES.payments.isSubscriptionPackEnabled(script.subscriptionPack))) {
            delete fusion_FUSION.availableScripts[key];
        }
    }

    return fusion_FUSION.availableScripts;
}

fusion_FUSION.getAllScripts = function() {
    if (WebRCP && WebRCP.platformManifest && WebRCP.platformManifest.isWidget)
        return fusion_FUSION.getFreeScripts();
    return fusion_FUSION.scripts;
}

fusion_FUSION.getFreeScripts = function () {
    if (fusion_FUSION.freeScripts) return fusion_FUSION.freeScripts;
    fusion_FUSION.freeScripts = JSON.parse(JSON.stringify(fusion_FUSION.scripts));

    const keys = Object.keys(fusion_FUSION.freeScripts);

    for (let key of keys) {
        const script = fusion_FUSION.freeScripts[key];

        if (script.subscriptionPack) {
            delete fusion_FUSION.freeScripts[key];
        }
    }

    return fusion_FUSION.freeScripts;
}



fusion_FUSION.scripts['MACD']= {
    title: 'macdTitle',
    description: 'macdDescription',
    type: 'indicators',
    newPane: true,
    centerZero:true,
    inputs: {

        'CLOSE': {type: 'series', name: 'price', properties: {def:'c'}, value: null},
        'FPERIOD': {type: 'integer', name: 'firstPeriod', properties: {def: 12, max: 100, min: 0}, value: 12},
        'SPERIOD': {type: 'integer', name: 'secondPeriod', properties: {def: 26, max: 100, min: 0}, value: 26},
        'SGPERIOD': {type: 'integer', name: 'signalPeriod', properties: {def: 9, max: 100, min: 0}, value: 9}

    },

    outputs: {

        'MACD': {
            type: 'series', series: {
                seriesId: null,
                title: 'macdTitle',
                labels: ['line', 'signal', 'histogram'],
                fields: ['MACDLine', 'MACDSignal', 'MACDHistogram'],
                data: null
            }
        }

    },

    plotters: [

        {type:'SeriesObject', dataLink: 'MACD', renderAs: 'Line and Histogram', dataField: 'MACDHistogram', color: '#ff9800', width: 1, dash:[], priceTag: false, priceLine: false},
        {type:'SeriesObject', dataLink: 'MACD', renderAs: 'Line', dataField: 'MACDSignal', color: '#f44336', width: 1, dash:[], priceTag: false, priceLine: false},
        {type:'SeriesObject', dataLink: 'MACD', renderAs: 'Line', dataField: 'MACDLine', color: '#00bcd4', width: 1.5, dash:[], priceTag: true, priceLine: true}


    ],

    controller: function (context, inputs, outputs) {

        var MACDController = function (context, inputs, outputs) {


            this.id			= '';
            this.context	= context;
            this.inputs 	= inputs;
            this.outputs	= outputs;

            this.init		= function () {

                this.helper = this.context.createSeries(['EMAF', 'EMAS', 'EMAG']);
                this.EMAF = this.context.getRawSeriesWrapper(this.helper, 'EMAF');
                this.EMAS = this.context.getRawSeriesWrapper(this.helper, 'EMAS');
                this.EMAG = this.context.getRawSeriesWrapper(this.helper, 'EMAG');

            }

            this.calculate	= function (index) {


                this.EMAF.setValue(index, fusion_FUSION.lib.getEMA(this.CLOSE, index, this.FPERIOD, this.EMAF));
                this.EMAS.setValue(index, fusion_FUSION.lib.getEMA(this.CLOSE, index, this.SPERIOD, this.EMAS));

                var fema = this.EMAF.getValue(index);
                var sema = this.EMAS.getValue(index);

                if (fema === null || sema === null) return;

                this.MACDLine.setValue(index, fema - sema);

                this.EMAG.setValue(index, fusion_FUSION.lib.getEMA(this.MACDLine, index, this.SGPERIOD, this.EMAG));
                var sgema = this.EMAG.getValue(index);
                this.MACDSignal.setValue (index, sgema);
                this.MACDHistogram.setValue (index, this.MACDLine.getValue(index) - this.MACDSignal.getValue(index));

            }

        };

        return new MACDController (context, inputs, outputs);
    }
}

