fusion_FUSION.scripts['DPO'] = {

    title: 'dpoTitle',
    description: 'dpoDescription',
    type: 'indicators',
    newPane: true,
    inputs: {
        'CLOSE': { type: 'series', name: 'price', properties: { def: 'c' }, value: null },
        'PERIODS': { type: 'integer', name: 'periods', properties: { max: 200, min: 0 }, value: 7 },
    },

    outputs: {
        'DPO': {
            type: 'series', series: {
                seriesId: null,
                title: 'dpoTitle',
                labels: ['value'],
                fields: ['DPOValue'],
                data: null
            }
        }
    },

    plotters: [
        { type: 'SeriesObject', dataLink: 'DPO', renderAs: 'Line', dataField: 'DPOValue', color: '#03a9f4', width: 1.5, dash: [], priceTag: true }
    ],
    controller: function (context, inputs, outputs) {

        var DPOController = function (context, inputs, outputs) {

            this.id = '';
            this.context = context;
            this.inputs = inputs;
            this.outputs = outputs;

            this.init = function () { }

            this.calculate = function (index) {
                var close = this.CLOSE.getValue(index);
                var ma = fusion_FUSION.lib.getMA(this.CLOSE, index, this.PERIODS);
                if (close === null || ma === null) return;

                this.DPOValue.setValue(index, close - ma);
            }
        };

        return new DPOController(context, inputs, outputs);
    }
}

fusion_FUSION.scripts['DMA'] = {
    title: 'dmaTitle',
    description: 'dmaDescription',
    type: 'indicators',
    newPane: false,
    inputs: {
        'CLOSE': { type: 'series', name: 'price', properties: { def: 'c' }, value: null },
        'PERIODS': { type: 'integer', name: 'periods', properties: { max: 200, min: 1 }, value: 3 },
        'DISPLACEMENT': { type: 'integer', name: 'displacement', properties: { max: 200, min: 1 }, value: 3 },
    },
    outputs: {
        'DMA': {
            type: 'series', series: {
                seriesId: null,
                title: 'dmaTitle',
                labels: ['value'],
                fields: ['DMA'],
                data: null
            }
        }
    },
    plotters: [{
        type: 'SeriesObject',
        dataLink: 'DMA',
        renderAs: 'Line',
        dataField: 'DMA',
        color: '#ff9800',
        width: 1.5,
        dash: []
    }],

    controller: function (context, inputs, outputs) {
        var DMAController = function (context, inputs, outputs) {
            this.id = '';
            this.context = context;
            this.inputs = inputs;
            this.outputs = outputs;

            this.init = function () { }

            this.calculate = function (index) {
                if (index < this.PERIODS) {
                    return;
                } else if (index < (this.DISPLACEMENT + this.PERIODS)) {
                    this.DMA.setValue(index + this.DISPLACEMENT, this.CLOSE.getValue(index));
                } else {
                    this.DMA.setValue(index + this.DISPLACEMENT, fusion_FUSION.lib.getMA(this.CLOSE, index, this.PERIODS));
                }
            }
        };

        return new DMAController(context, inputs, outputs);
    }
}

